const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const token = flow.get('oauth_token');
const expiry = flow.get('oauth_token_expiry') || 0;
const now = Date.now();

// Token valid with 60s buffer
if (token && expiry - now > 60000) {
    node.status({ fill: 'green', shape: 'dot', text: formatStatus('Token valid') });
    return [msg, null];
}

// Need refresh
node.status({ fill: 'yellow', shape: 'ring', text: formatStatus('Refreshing token...') });
return [null, msg];

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

if (msg.statusCode !== 200 || !msg.payload.access_token) {
    node.status({ fill: 'red', shape: 'ring', text: formatStatus('Token refresh failed') });
    node.error('OAuth token refresh failed', msg);
    return null;
}

flow.set('oauth_token', msg.payload.access_token);
// expires_in is in seconds; store as ms timestamp with 60s buffer
flow.set('oauth_token_expiry', Date.now() + (msg.payload.expires_in * 1000));

node.status({ fill: 'green', shape: 'dot', text: formatStatus('Token refreshed') });
return msg;

const secrets = global.get('config')?.secrets?.google_calendar;

msg.payload = new URLSearchParams({
    grant_type: 'refresh_token',
    refresh_token: secrets.refresh_token,
    client_id: secrets.client_id,
    client_secret: secrets.client_secret
}).toString();

msg.headers = { 'Content-Type': 'application/x-www-form-urlencoded' };
return msg;

const secrets = global.get('config')?.secrets?.google_calendar;
const token = flow.get('oauth_token');
const location = global.get('config')?.location;

const now = new Date();
const windowEnd = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);

const timeMin = now.toISOString();
const timeMax = windowEnd.toISOString();

const calendarMap = {
    [secrets.appointments_calendar_id]: 'appointments',
    [secrets.reminders_calendar_id]: 'reminders',
    [secrets.trash_calendar_id]: 'trash'
};

// Clear any previous requests which might not have complted the entire series.
flow.set('calendar_responses', []);

// Store calendar map and window for downstream nodes
flow.set('calendar_map', calendarMap);
flow.set('poll_window', { timeMin, timeMax, timezone: location?.timezone || 'America/New_York' });

// Fan out one message per calendar
const calendars = Object.keys(calendarMap);
for (const calendarId of calendars) {
    const params = new URLSearchParams({
        timeMin,
        timeMax,
        singleEvents: 'true',
        orderBy: 'startTime'
    });

    node.send({
        calendarId,
        url: `https://www.googleapis.com/calendar/v3/calendars/${encodeURIComponent(calendarId)}/events?${params}`,
        headers: { Authorization: `Bearer ${token}` },
        payload: ''
    });
}

return null;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

if (msg.statusCode !== 200) {
    node.error(`Calendar fetch failed for ${msg.calendarId}: ${msg.statusCode}`, msg);
    return null;
}

const responses = flow.get('calendar_responses') || [];
responses.push({ calendarId: msg.calendarId, items: msg.payload.items || [] });
flow.set('calendar_responses', responses);

if (responses.length < 3) {
    node.status({ fill: 'yellow', shape: 'ring', text: formatStatus(`${responses.length}/3 calendars fetched`) });
    return null;
}

// All three received — clear and proceed
flow.set('calendar_responses', []);
node.status({ fill: 'green', shape: 'dot', text: formatStatus('All calendars fetched') });
msg.responses = responses;
return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const calendarMap = flow.get('calendar_map');
const { timeMin, timeMax, timezone } = flow.get('poll_window');

const events = [];

for (const { calendarId, items } of msg.responses) {
    const category = calendarMap[calendarId];

    for (const item of items) {
        const allDay = !!item.start.date; // all-day events use start.date, not start.dateTime

        // Normalize to local date/time strings
        const startRaw = allDay ? item.start.date : item.start.dateTime;
        const endRaw = allDay ? item.end.date : item.end.dateTime;

        // For all-day events, date is already YYYY-MM-DD local
        // For timed events, parse dateTime and convert to local
        let date, start, end;

        if (allDay) {
            date = startRaw; // YYYY-MM-DD
        } else {
            // Extract local date from dateTime (may have offset)
            const startDate = new Date(startRaw);
            date = startDate.toLocaleDateString('en-CA', { timeZone: timezone }); // YYYY-MM-DD
            start = startDate.toLocaleString('sv-SE', { timeZone: timezone }).replace(' ', 'T');
            const endDate = new Date(endRaw);
            end = endDate.toLocaleString('sv-SE', { timeZone: timezone }).replace(' ', 'T');
        }

        const event = {
            id: item.id,
            calendar: category,
            title: item.summary || '(No title)',
            date,
            all_day: allDay
        };

        if (!allDay) {
            event.start = start;
            event.end = end;
        }

        events.push(event);
    }
}

// Sort chronologically — all-day first within each day, then by time
events.sort((a, b) => {
    const aKey = a.start || a.date + 'T00:00:00';
    const bKey = b.start || b.date + 'T00:00:00';
    return aKey.localeCompare(bKey);
});

node.status({ fill: 'green', shape: 'dot', text: formatStatus(`${events.length} event(s) classified`) });
msg.events = events;
return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const { timeMin, timeMax } = flow.get('poll_window');

msg.topic = 'highland/state/calendar/snapshot';
msg.retain = true;
msg.qos = 1;
msg.payload = JSON.stringify({
    timestamp: new Date().toISOString(),
    source: 'calendaring',
    window_start: timeMin,
    window_end: timeMax,
    events: msg.events
});

node.status({ fill: 'green', shape: 'dot', text: formatStatus(`Snapshot: ${msg.events.length} event(s)`) });
return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
node.status({ fill: 'red', shape: 'ring', text: formatStatus(`Error: ${msg.error?.message || 'unknown'}`) });
node.warn(msg.error);
// Future: publish to highland/event/notify for persistent API failures
return null;
